 1→import React from 'react';
 2→import ReactDOM from 'react-dom/client';
 3→import App from './app/App';
 4→import './styles/global.css';
 5→
 6→ReactDOM.createRoot(document.getElementById('root')).render(
 7→  <React.StrictMode>
 8→    <App />
