  1→import { generateId } from './ids';
  2→import { CURRENT_PROJECT_VERSION } from './projectVersion';
  3→import { WALL_THICKNESS, WALL_HEIGHT, DOOR_WIDTH, DOOR_HEIGHT, DOOR_SILL_HEIGHT, WINDOW_WIDTH, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT, COLUMN_WIDTH, COLUMN_DEPTH, BEAM_WIDTH, BEAM_DEPTH, STAIR_WIDTH, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, SLAB_THICKNESS, SLAB_ELEVATION, SECTION_DEPTH, LANDING_WIDTH, LANDING_DEPTH, LANDING_THICKNESS, RAILING_HEIGHT, RAILING_WIDTH, ROOM_COLOR, DIMENSION_DEFAULT_OFFSET } from './defaults';
  4→import { FIXTURE_DEFAULTS } from '@/editor/tools';
  5→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
  6→
  7→export function createProject(name = 'Untitled Project') {
  8→  return {
  9→    id: generateId('proj'),
 10→    name,
 11→    address: '',
 12→    documentDefaults: {
 13→      drawnBy: '',
 14→      checkedBy: '',
 15→    },
 16→    createdAt: new Date().toISOString(),
 17→    updatedAt: new Date().toISOString(),
 18→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 19→    roofSystem: null,
 20→    trussSystems: [],
 21→    sheets: [],
 22→    phases: [],
 23→    version: CURRENT_PROJECT_VERSION,
 24→  };
 25→}
 26→
 27→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 28→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 29→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 30→
 31→  return {
 32→    id: generateId('floor'),
 33→    name,
 34→    levelIndex,
 35→    elevation,
 36→    floorToFloorHeight,
 37→    walls: [],
 38→    rooms: [],
 39→    doors: [],
 40→    windows: [],
 41→    columns: [],
 42→    beams: [],
 43→    stairs: [],
 44→    landings: [],
 45→    fixtures: [],
 46→    annotations: [],
 47→    annotationSettings: createAnnotationSettings(),
 48→    slabs: [],
 49→    sectionCuts: [],
 50→    railings: [],
 51→  };
 52→}
 53→
 54→export function nextSectionLabel(existingCuts = []) {
 55→  const usedLetters = new Set(
 56→    existingCuts
 57→      .map(c => {
 58→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 59→        return match ? match[1] : null;
 60→      })
 61→      .filter(Boolean)
 62→  );
 63→  for (let i = 0; i < 26; i++) {
 64→    const letter = String.fromCharCode(65 + i);
 65→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 66→  }
 67→  return `Section ${existingCuts.length + 1}`;
 68→}
 69→
 70→export function createAnnotationSettings(overrides = {}) {
 71→  return {
 72→    showWallDimensions: overrides.showWallDimensions ?? true,
 73→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 74→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 75→    showObjectTags: overrides.showObjectTags ?? true,
 76→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 77→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 78→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 79→  };
 80→}
 81→
 82→export function createLinearDimensionAnnotation(startPoint, endPoint, options = {}) {
 83→  return {
 84→    id: generateId('anno'),
 85→    type: 'dimension',
 86→    mode: options.mode ?? 'aligned',
 87→    startPoint: { x: startPoint.x, y: startPoint.y },
 88→    endPoint: { x: endPoint.x, y: endPoint.y },
 89→    offset: options.offset ?? DIMENSION_DEFAULT_OFFSET,
 90→    textOverride: options.textOverride ?? '',
 91→  };
 92→}
 93→
 94→export function createWall(start, end, thickness = WALL_THICKNESS, options = {}) {
 95→  return {
 96→    id: generateId('wall'),
 97→    start: { x: start.x, y: start.y },
 98→    end: { x: end.x, y: end.y },
 99→    thickness,
100→    height: options.height ?? WALL_HEIGHT,
101→    startAttachment: options.startAttachment ?? null,
102→    endAttachment: options.endAttachment ?? null,
103→  };
104→}
105→
106→export function createDoor(wallId, offset, width = DOOR_WIDTH, openDirection = 'left', type = 'swing') {
107→  return {
108→    id: generateId('door'),
109→    wallId,
110→    offset,
111→    width,
112→    height: DOOR_HEIGHT,
113→    sillHeight: DOOR_SILL_HEIGHT,
114→    openDirection,
115→    type,
116→  };
117→}
118→
119→export function createWindow(wallId, offset, width = WINDOW_WIDTH, type = 'standard', openDirection = 'left') {
120→  return {
121→    id: generateId('win'),
122→    wallId,
123→    offset,
124→    width,
125→    height: WINDOW_HEIGHT,
126→    sillHeight: WINDOW_SILL_HEIGHT,
127→    type,
128→    openDirection,
129→  };
130→}
131→
132→export function createColumn(x, y, width = COLUMN_WIDTH, depth = COLUMN_DEPTH, options = {}) {
133→  return {
134→    id: generateId('col'),
135→    x, y, width, depth,
136→    height: options.height ?? 3000,
137→    rotation: options.rotation ?? 0,
138→    type: options.type ?? 'rectangular',
139→    name: options.name ?? '',
140→    showLabel: options.showLabel ?? false,
141→  };
142→}
143→
144→export function createBeam(startRef, endRef, width = BEAM_WIDTH, depth = BEAM_DEPTH, floorLevel = 0) {
145→  return {
146→    id: generateId('beam'),
147→    startRef: { ...startRef },
148→    endRef: { ...endRef },
149→    width,
150→    depth,
151→    floorLevel,
152→  };
153→}
154→
155→export function createSlab(floorId, boundaryPoints = [], thickness = SLAB_THICKNESS, elevation = SLAB_ELEVATION, options = {}) {
156→  return {
157→    id: generateId('slab'),
158→    floorId,
159→    boundaryPoints: boundaryPoints.map(point => ({ x: point.x, y: point.y })),
160→    thickness,
161→    elevation,
162→    name: options.name ?? '',
163→    type: options.type ?? '',
164→  };
165→}
166→
167→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}, options = {}) {
168→  return {
169→    id: generateId('stair'),
170→    startPoint: { x: startPoint.x, y: startPoint.y },
171→    width,
172→    numberOfRisers,
173→    riserHeight,
174→    treadDepth,
175→    direction: {
176→      angle: direction?.angle ?? 0,
177→    },
178→    floorRelation: {
179→      fromFloorId: floorRelation.fromFloorId ?? null,
180→      toFloorId: floorRelation.toFloorId ?? null,
181→    },
182→    startLandingAttachment: options.startLandingAttachment ?? null,
183→    endLandingAttachment: options.endLandingAttachment ?? null,
184→    roofAccess: options.roofAccess ?? null,
185→  };
186→}
187→
188→export function createLanding(position, width = LANDING_WIDTH, depth = LANDING_DEPTH, options = {}) {
189→  return {
190→    id: generateId('landing'),
191→    position: { x: position.x, y: position.y },
192→    width,
193→    depth,
194→    thickness: options.thickness ?? LANDING_THICKNESS,
195→    elevation: options.elevation ?? 0,
196→    rotation: options.rotation ?? 0,
197→  };
198→}
