   9→function sanitizeFileName(name = 'sheet') {
  10→  return name
  11→    .trim()
  12→    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '-')
  13→    .replace(/\s+/g, ' ')
  14→    .slice(0, 120)
