  18→function downloadBlob(blob, fileName) {
  19→  const url = URL.createObjectURL(blob);
  20→  const link = document.createElement('a');
  21→  link.href = url;
  22→  link.download = fileName;
  23→  document.body.appendChild(link);
  24→  link.click();
  25→  link.remove();
  26→  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
  27→}
  28→
  29→function applyComputedSvgStyle(sourceElement, targetElement) {
  30→  const style = window.getComputedStyle(sourceElement);
  31→  const properties = [
  32→    'fill',
  33→    'fill-opacity',
  34→    'stroke',
  35→    'stroke-opacity',
  36→    'stroke-width',
  37→    'stroke-linecap',
  38→    'stroke-linejoin',
  39→    'stroke-dasharray',
  40→    'opacity',
  41→    'font-size',
  42→    'font-family',
  43→    'font-weight',
  44→    'letter-spacing',
  45→    'text-anchor',
  46→    'dominant-baseline',
  47→  ];
  48→
  49→  for (const property of properties) {
  50→    const value = style.getPropertyValue(property);
  51→    if (value) {
  52→      targetElement.style.setProperty(property, value);
  53→    }
  54→  }
  55→}
  56→
  57→function inlineComputedStyles(sourceRoot, clonedRoot) {
  58→  const sourceNodes = [sourceRoot, ...sourceRoot.querySelectorAll('*')];
  59→  const clonedNodes = [clonedRoot, ...clonedRoot.querySelectorAll('*')];
  60→
  61→  for (let index = 0; index < sourceNodes.length; index += 1) {
  62→    applyComputedSvgStyle(sourceNodes[index], clonedNodes[index]);
  63→  }
  64→}
  65→
  66→function serializeSvg(svgElement) {
  67→  const clone = svgElement.cloneNode(true);
  68→  clone.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
  69→  clone.setAttribute('xmlns:xlink', 'http://www.w3.org/1999/xlink');
  70→  clone.removeAttribute('style');
  71→
  72→  if (!clone.getAttribute('viewBox')) {
  73→    const width = clone.getAttribute('width') || '100';
  74→    const height = clone.getAttribute('height') || '100';
  75→    clone.setAttribute('viewBox', `0 0 ${width} ${height}`);
  76→  }
  77→
  78→  inlineComputedStyles(svgElement, clone);
  79→  return new XMLSerializer().serializeToString(clone);
  80→}
  81→
  82→function createImageFromSvgString(svgString) {
  83→  return new Promise((resolve, reject) => {
  84→    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
  85→    const url = URL.createObjectURL(blob);
  86→    const image = new Image();
  87→    image.onload = () => {
  88→      URL.revokeObjectURL(url);
  89→      resolve(image);
  90→    };
  91→    image.onerror = (error) => {
  92→      URL.revokeObjectURL(url);
  93→      reject(error);
  94→    };
  95→    image.src = url;
  96→  });
  97→}
  98→
  99→function getCanvasScaleFromDpi(dpi) {
 100→  return Math.max(1, (Number(dpi) || DEFAULT_PNG_DPI) / MM_PER_INCH);
 101→}
 102→
 103→function loadImage(src) {
 104→  return new Promise((resolve, reject) => {
 105→    const img = new Image();
 106→    img.onload = () => resolve(img);
 107→    img.onerror = reject;
 108→    img.src = src;
 109→  });
 110→}
