 166→function escapePdfText(value = '') {
 167→  return String(value)
 168→    .replace(/[^\x20-\x7E]/g, '?')
 169→    .replace(/\\/g, '\\\\')
 170→    .replace(/\(/g, '\\(')
 171→    .replace(/\)/g, '\\)');
