 179→function parsePoints(points = '') {
 180→  const values = parseNumberList(points);
 181→  const result = [];
 182→  for (let index = 0; index < values.length; index += 2) {
 183→    result.push({ x: values[index], y: values[index + 1] });
 184→  }
 185→  return result;
 186→}
