  const angleDeg = (info.angle * 180) / Math.PI;

  return (
    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
      <line
        x1={0} y1={0}
        x2={0} y2={flipSign * -door.width}
        stroke={DRAWING_GRAPHICS.plan.markerStroke}
        strokeWidth={1.1}
        vectorEffect="non-scaling-stroke"
