 109→function updateRoofSystem(state, updater, recordHistory = true) {
 110→  const nextRoofSystem = updater(state.project.roofSystem);
 111→  return applyProjectUpdate(state, {
 112→    ...state.project,
 113→    updatedAt: new Date().toISOString(),
 114→    roofSystem: nextRoofSystem,
 115→  }, recordHistory);
 116→}
