  1→import { useMemo, useRef } from 'react';
  2→import { TOOLS } from './tools';
  3→import { createWallDrawHandler } from './handlers/wallDrawHandler';
  4→import { createSelectHandler } from './handlers/selectHandler';
  5→import { createDimensionPlaceHandler } from './handlers/dimensionPlaceHandler';
  6→import { createDoorPlaceHandler } from './handlers/doorPlaceHandler';
  7→import { createWindowPlaceHandler } from './handlers/windowPlaceHandler';
  8→import { createColumnPlaceHandler } from './handlers/columnPlaceHandler';
  9→import { createRoomPlaceHandler } from './handlers/roomPlaceHandler';
 10→import { createBeamPlaceHandler } from './handlers/beamPlaceHandler';
 11→import { createSlabPlaceHandler } from './handlers/slabPlaceHandler';
 12→import { createStairPlaceHandler } from './handlers/stairPlaceHandler';
 13→import { createSectionPlaceHandler } from './handlers/sectionPlaceHandler';
 14→import { createLandingPlaceHandler } from './handlers/landingPlaceHandler';
 15→import { createFixturePlaceHandler } from './handlers/fixturePlaceHandler';
 16→import { createRailingPlaceHandler } from './handlers/railingPlaceHandler';
 17→import { createElevationSelectHandler } from './handlers/elevationSelectHandler';
 18→import { createRoofSelectHandler } from './handlers/roofSelectHandler';
 19→import { createRoofParapetPlaceHandler } from './handlers/roofParapetPlaceHandler';
 20→import { createRoofDrainPlaceHandler } from './handlers/roofDrainPlaceHandler';
 21→import { createRoofOpeningPlaceHandler } from './handlers/roofOpeningPlaceHandler';
 22→import { createTrussSelectHandler } from './handlers/trussSelectHandler';
 23→import { createTrussDrawHandler } from './handlers/trussDrawHandler';
 24→
 25→function createReadOnlyHandler() {
 26→  return {
 27→    onMouseDown() {},
 28→    onMouseMove() {},
 29→    onMouseUp() {},
 30→    onDoubleClick() {},
 31→    onKeyDown() {},
 32→    getCursor() {
 33→      return 'default';
 34→    },
 35→  };
 36→}
 37→
 38→export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, roofSystem, trussSystems, modelTarget, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode, activePhaseId }) {
 39→  const getFloorRef = useRef(getFloor);
 40→  getFloorRef.current = getFloor;
 41→
 42→  const handler = useMemo(() => {
 43→    if (modelTarget === 'truss') {
 44→      if (viewMode !== 'plan') {
 45→        return createReadOnlyHandler();
 46→      }
 47→
 48→      const trussCtx = {
 49→        dispatch,
 50→        editorDispatch,
 51→        getFloor: (...args) => getFloorRef.current(...args),
 52→        activeFloorId,
 53→        trussSystems,
 54→        viewport,
 55→        selectedId,
 56→        selectedType,
 57→        viewMode,
 58→        activePhaseId,
 59→      };
 60→
 61→      switch (activeTool) {
 62→        case TOOLS.TRUSS_DRAW:
 63→          return createTrussDrawHandler(trussCtx);
 64→        case TOOLS.SELECT:
 65→        default:
 66→          return createTrussSelectHandler(trussCtx);
 67→      }
 68→    }
 69→
 70→    if (modelTarget === 'roof') {
 71→      if (viewMode !== 'plan') {
 72→        return createReadOnlyHandler();
 73→      }
 74→
 75→      const roofCtx = {
 76→        dispatch,
 77→        editorDispatch,
 78→        roofSystem,
 79→        viewport,
 80→      };
 81→
 82→      switch (activeTool) {
 83→        case TOOLS.ROOF_PARAPET:
 84→          return createRoofParapetPlaceHandler(roofCtx);
 85→        case TOOLS.ROOF_DRAIN:
 86→          return createRoofDrainPlaceHandler(roofCtx);
 87→        case TOOLS.ROOF_OPENING:
 88→          return createRoofOpeningPlaceHandler(roofCtx);
 89→        case TOOLS.SELECT:
 90→        default:
 91→          return createRoofSelectHandler(roofCtx);
 92→      }
 93→    }
 94→
 95→    if (viewMode?.startsWith('elevation_')) {
 96→      return createElevationSelectHandler({
 97→        dispatch,
 98→        editorDispatch,
 99→        project,
100→        getFloor: (...args) => getFloorRef.current(...args),
101→        activeFloorId,
102→        viewport,
103→        snapEnabled,
104→        viewMode,
105→      });
106→    }
107→
108→    if (viewMode !== 'plan') {
109→      return createReadOnlyHandler();
110→    }
111→
112→    const ctx = {
113→      dispatch, editorDispatch,
114→      getFloor: (...args) => getFloorRef.current(...args),
115→      activeFloorId, viewport, snapEnabled, activePhaseId,
116→    };
117→
118→    switch (activeTool) {
119→      case TOOLS.DIMENSION:
120→        return createDimensionPlaceHandler(ctx);
121→      case TOOLS.WALL:
122→        return createWallDrawHandler(ctx);
123→      case TOOLS.BEAM:
124→        return createBeamPlaceHandler(ctx);
125→      case TOOLS.STAIR:
126→        return createStairPlaceHandler(ctx);
127→      case TOOLS.SECTION:
128→        return createSectionPlaceHandler(ctx);
129→      case TOOLS.SLAB:
130→        return createSlabPlaceHandler(ctx);
131→      case TOOLS.ROOM:
132→        return createRoomPlaceHandler(ctx);
133→      case TOOLS.SELECT:
134→        return createSelectHandler(ctx);
135→      case TOOLS.DOOR:
136→        return createDoorPlaceHandler(ctx);
137→      case TOOLS.WINDOW:
138→        return createWindowPlaceHandler(ctx);
139→      case TOOLS.COLUMN:
140→        return createColumnPlaceHandler(ctx);
141→      case TOOLS.LANDING:
142→        return createLandingPlaceHandler(ctx);
143→      case TOOLS.FIXTURE:
144→        return createFixturePlaceHandler(ctx);
145→      case TOOLS.RAILING:
146→        return createRailingPlaceHandler(ctx);
147→      default:
148→        return null;
149→    }
150→  }, [activeTool, activeFloorId, project, roofSystem, trussSystems, modelTarget, viewport.zoom, snapEnabled, viewMode, activePhaseId, selectedId, selectedType]);
151→
152→  return {
153→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
154→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
155→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
156→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
157→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
158→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
159→  };
160→}
